export type Cell = [number, number];

type CellCount = { cell: Cell; count: number };

export function nextGeneration(cells: Cell[]): Cell[] {
  const key = ([x, y]: Cell) => `${x},${y}`;
  const alive = new Set(cells.map(key));
  const neighbourCounts = new Map<string, CellCount>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbour: Cell = [x + dx, y + dy];
        const k = key(neighbour);
        const entry = neighbourCounts.get(k);
        if (entry) entry.count++;
        else neighbourCounts.set(k, { cell: neighbour, count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighbourCounts) {
    if (count === 3 || (count === 2 && alive.has(k))) result.push(cell);
  }

  return result;
}

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const key = ([x, y]: Cell) => `${x},${y}`;
  const alive = new Set(cells.map(key));
  const neighbourCounts = new Map<string, number>();
  const cellByKey = new Map<string, Cell>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbour: Cell = [x + dx, y + dy];
        const k = key(neighbour);
        neighbourCounts.set(k, (neighbourCounts.get(k) ?? 0) + 1);
        cellByKey.set(k, neighbour);
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighbourCounts) {
    if (count === 3 || (count === 2 && alive.has(k))) {
      result.push(cellByKey.get(k)!);
    }
  }

  return result;
}

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const alive = new Set(cells.map(([x, y]) => key(x, y)));
  const neighbourCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighbourCounts.set(k, (neighbourCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighbourCounts) {
    const [xs, ys] = k.split(",");
    const cell: Cell = [Number(xs), Number(ys)];
    if (count === 3 || (count === 2 && alive.has(k))) result.push(cell);
  }

  return result;
}
